# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import os
from datetime import datetime

class FileAccessControlSystem:
    def __init__(self, db_connection):
        self.db = db_connection

    def check_permission(self, user, file_path):
        # Query the database to get the user's access level for the file
        query = "SELECT access_level FROM users WHERE username = %s AND file_path = %s"
        params = (user, file_path)
        result = self.db.query(query, params)

        # Check if the user has permission to read the file
        if result[0]['access_level'] >= 1:
            return True
        else:
            return False

    def open_file(self, user, file_path):
        # Check if the user has permission to read the file
        if not self.check_permission(user, file_path):
            raise Exception("User does not have permission to read this file")

        # Open and return the file contents
        with open(file_path, 'r') as f:
            return f.read()